using namespace std;
il ll read()
{
    ll x=0,f=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=getchar();}
    return x*f;
}
void write(ll x)
{
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e5+5;
ll n,m,cnt,s,a[MAXN],l=0;
int main(void)
{
	n=read(),m=read();
	m<<=1;
	FOR(i,1,n-1)a[i]=read();
	FOR(i,1,n-1)
    {
		while(l<n&&s<m)
        {
            s+=a[++l];
        }
		cnt=max(cnt,l-i+1);
		s-=a[i];
	}
    write(cnt);
	return 0;
}
